import pypdf
def dump(f, maxdepth=3):
    r=pypdf.PdfReader(f+".pdf")
    print(f"\n########## OUTLINE: {f} ({len(r.pages)} pages) ##########")
    try:
        ol=r.outline
    except Exception as e:
        print("no outline:",e); return
    def walk(items, depth=0):
        for it in items:
            if isinstance(it, list):
                if depth<maxdepth: walk(it, depth+1)
            else:
                try:
                    pg=r.get_destination_page_number(it)+1
                except Exception:
                    pg='?'
                print("  "*depth, f"[p{pg}]", it.title)
    walk(ol)
for f in ["mumford-abelian-varieties","fga-explained"]:
    dump(f)
